INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-e3452428-moex-00093', 'elementary-e3452428', 'elementary-e3452428-moex-114-34c7f7f6', 'sub-elementary-e3452428-02', NULL, 'single_choice', '落日千林紫，漁舟聚淺灘。飛蓬雲外沒，野鳥望中還。寺小藏深樹，潮寬點亂山。一樽頻對 此，無意羨人間。（宋懋澄〈晚色〉） 根據上詩，下列敘述何者正確？', '["刻畫景物，藉景抒情", "蘊含瀟灑的出世之想", "充滿山水意趣，富有情韻", "描寫晚景，宛如一幅山水畫卷 近似「夕陽無限好，只是近黃昏」之意"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:04+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般民政"}'::jsonb, NULL),
  ('elementary-e3452428-moex-00094', 'elementary-e3452428', 'elementary-e3452428-moex-114-34c7f7f6', 'sub-elementary-e3452428-02', NULL, 'single_choice', '「畫家在素描時，勒定了所畫對象大約的輪廓後，只以炭筆磨擦出光影的陰暗與明亮，而不 做細部的描繪，保持一點朦朧感，以免整個畫面過於呆板。這個階段，就像詩一樣，在光與 暗、有與無之間，帶著一點迷濛，一點神祕，一點耐人追索的況味。然而這並非脫離現實， 仔細想想，我們在人生裡，大多數的情感都是這樣迷濛的吧！誰能肯定自己的內心無論是哪 一刻都清晰無比的呢？」 根據上文，下列選項正確的是：', '["擅長讀詩的人擁有最單純的心思，對世事經常感到懵懵懂懂", "詩在指涉、內涵上的模糊性，常能帶給讀者解釋探索的趣味", "詩與素描一樣，都不可進行細部描繪，才能提升整體的美感", "思緒清明的人難以享受讀詩之樂，因複雜處能輕易迎刃而解 生命中多數情感一如詩般迷濛，從詩中可以體會人生與現實"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:04+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般民政"}'::jsonb, NULL),
  ('elementary-e3452428-moex-00095', 'elementary-e3452428', 'elementary-e3452428-moex-114-34c7f7f6', 'sub-elementary-e3452428-02', NULL, 'single_choice', '「ChatGPT或Bing Chat多是提供定義式的短語，回覆的內容主要是『已知』的有限資訊， 難以『多義性』的語言表現感知複雜的人類思維。這是因為 AI 的訓練出自設計者目前的偏 好或定見，如果想讓AI更貼近人類需求，就必須仰賴人類持續更新且多樣化的經驗。」 根據上文，下列選項正確的是：', '["目前AI程式設計者偏好取樣多元的生活經驗", "AI現在仍未取代人類思想情感的複雜性表現", "AI設計者皆偏愛不受感知影響的科學性語言", "目前AI是以短語提供快速單一的資訊為目的 不斷轉型的語言文化和科技趨勢無直接關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:04+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般民政"}'::jsonb, NULL),
  ('elementary-e3452428-moex-00096', 'elementary-e3452428', 'elementary-e3452428-moex-114-20ccded8', 'sub-elementary-e3452428-03', NULL, 'single_choice', '有關地方自治團體法定地位或組織之意涵，下列何者錯誤？', '["地方自治團體公務人員由中央政府直接任命", "地方自治團體掌理事項包括自治事項及委辦事項", "地方自治團體具有公法人資格", "地方自治團體是基於因地制宜的需要而發展出來的組織"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:04+00:00", "source_pdf_sha1": "e95e74a28d4a", "answer_pdf_sha1": "24969c6401d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "502", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "地方自治大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般民政"}'::jsonb, NULL),
  ('elementary-e3452428-moex-00097', 'elementary-e3452428', 'elementary-e3452428-moex-114-20ccded8', 'sub-elementary-e3452428-03', NULL, 'single_choice', '有關我國地方自治的敘述，下列何者錯誤？', '["地方立法機關得透過決議拒絕委辦事項", "地方自治團體是地域團體公法人", "縣自治為我國憲法保障的政治制度", "核心內涵包括團體自治與住民自治"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:04+00:00", "source_pdf_sha1": "e95e74a28d4a", "answer_pdf_sha1": "24969c6401d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "502", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "地方自治大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般民政"}'::jsonb, NULL),
  ('elementary-e3452428-moex-00098', 'elementary-e3452428', 'elementary-e3452428-moex-114-20ccded8', 'sub-elementary-e3452428-03', NULL, 'single_choice', '地方自治團體從事下列自治作為時，何者須經上級政府或主管機關核定？', '["縣（市）長任命副縣（市）長", "鄉（鎮、市）或村（里）名稱變更", "縣（市）議會發布自律規則", "縣（市）政府發布停車場設置自治條例"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:04+00:00", "source_pdf_sha1": "e95e74a28d4a", "answer_pdf_sha1": "24969c6401d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "502", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "地方自治大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般民政"}'::jsonb, NULL),
  ('elementary-e3452428-moex-00099', 'elementary-e3452428', 'elementary-e3452428-moex-114-20ccded8', 'sub-elementary-e3452428-03', NULL, 'single_choice', '有關直轄市自治規則之敘述，下列何者正確？', '["自治規則發布後，除應送行政院備查外，亦應函送直轄市議會查照", "除得規範直轄市之自治事項外，亦得規範委辦事項", "得使用「要點」作為其名稱", "僅得基於法律、法律授權之法規、自治條例之授權訂定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:04+00:00", "source_pdf_sha1": "e95e74a28d4a", "answer_pdf_sha1": "24969c6401d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "502", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "地方自治大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般民政"}'::jsonb, NULL),
  ('elementary-e3452428-moex-00100', 'elementary-e3452428', 'elementary-e3452428-moex-114-20ccded8', 'sub-elementary-e3452428-03', NULL, 'single_choice', '依司法院大法官解釋意旨，關於地方自治之敘述，下列何者正確？', '["基於共和國之理念與水平分權之功能，地方自治團體設有地方行政與立法機關之自治組織", "依據憲法關於中央與地方權限劃分之規定，地方自治團體在特定事務之執行上乃獨立於中央而與之分 權相抗", "凡憲法上之各級地域團體享有就所有事項制定規章並執行之權，且具有自主組織權限者，方得為地方自 治團體性質之公法人", "地方自治團體為與中央政府共享統治權行使之主體，其與中央之關係為共同協力關係"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:04+00:00", "source_pdf_sha1": "e95e74a28d4a", "answer_pdf_sha1": "24969c6401d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "502", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "地方自治大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般民政"}'::jsonb, NULL),
  ('elementary-e3452428-moex-00101', 'elementary-e3452428', 'elementary-e3452428-moex-114-20ccded8', 'sub-elementary-e3452428-03', NULL, 'single_choice', '若縣政府發現所轄鄉公所可能有依法應作為而不作為之情事，導致民眾權益受到嚴重影響，該縣政府決定 代行處理，依地方制度法規定，下列敘述何者正確？', '["縣政府需命鄉公所於一定期限內為之，逾期仍不作為者，才能代行處理", "縣政府應請內政部函知鄉公所此項處分決定", "鄉公所若認為代行處理有違法之嫌，可提出行政救濟", "代行處理所產生之費用，由兩機關共同分攤"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:04+00:00", "source_pdf_sha1": "e95e74a28d4a", "answer_pdf_sha1": "24969c6401d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "502", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "地方自治大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般民政"}'::jsonb, NULL),
  ('elementary-e3452428-moex-00102', 'elementary-e3452428', 'elementary-e3452428-moex-114-20ccded8', 'sub-elementary-e3452428-03', NULL, 'single_choice', '有關地方民意代表享有不受逮捕權的敘述，下列何者錯誤？', '["其立法目的在防止司法權或行政權妨害議員之身體自由，阻礙地方立法機關功能之發揮", "此項保障隨議員身分的喪失而消滅", "地方民意代表如屬現行犯則不適用", "地方民意代表在任期中任何時間皆享有"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:04+00:00", "source_pdf_sha1": "e95e74a28d4a", "answer_pdf_sha1": "24969c6401d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "502", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "地方自治大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般民政"}'::jsonb, NULL)
